846                                           const DataLayout &DL) {
847   Type *Ty = To->getType();
848   assert(U->getType() == Ty && "values must have matching types");
849   // Not a pointer, just return true.
850   if (!Ty->isPtrOrPtrVectorTy())
851     return true;
