7064 /// This is the function that does the work of looking through basic
7065 /// ptrtoint+arithmetic+inttoptr sequences.
7066 static const Value *getUnderlyingObjectFromInt(const Value *V) {
7067   do {
7068     if (const Operator *U = dyn_cast<Operator>(V)) {
7069       // If we find a ptrtoint, we can transfer control back to the
7070       // regular getUnderlyingObjectFromInt.
7071       if (U->getOpcode() == Instruction::PtrToInt)
7072         return U->getOperand(0);
7073       // If we find an add of a constant, a multiplied value, or a phi, it's
7074       // likely that the other operand will lead us to the base
7075       // object. We don't have to worry about the case where the
7076       // object address is somehow being computed by the multiply,
7077       // because our callers only care when the result is an
7078       // identifiable object.
7079       if (U->getOpcode() != Instruction::Add ||
7080           (!isa<ConstantInt>(U->getOperand(1)) &&
7081            Operator::getOpcode(U->getOperand(1)) != Instruction::Mul &&
7082            !isa<PHINode>(U->getOperand(1))))
7083         return V;
7084       V = U->getOperand(0);
7085     } else {
7086       return V;
7087     }
7088     assert(V->getType()->isIntegerTy() && "Unexpected operand type!");
7089   } while (true);
7090 }
