7128 AllocaInst *llvm::findAllocaForValue(Value *V, bool OffsetZero) {
7129   AllocaInst *Result = nullptr;
7130   SmallPtrSet<Value *, 4> Visited;
7131   SmallVector<Value *, 4> Worklist;
7132 
7133   auto AddWork = [&](Value *V) {
7134     if (Visited.insert(V).second)
7135       Worklist.push_back(V);
7136   };
7137 
7138   AddWork(V);
7139   do {
7140     V = Worklist.pop_back_val();
7141     assert(Visited.count(V));
7142 
7143     if (AllocaInst *AI = dyn_cast<AllocaInst>(V)) {
7144       if (Result && Result != AI)
7145         return nullptr;
7146       Result = AI;
7147     } else if (CastInst *CI = dyn_cast<CastInst>(V)) {
7148       AddWork(CI->getOperand(0));
7149     } else if (PHINode *PN = dyn_cast<PHINode>(V)) {
7150       for (Value *IncValue : PN->incoming_values())
7151         AddWork(IncValue);
7152     } else if (auto *SI = dyn_cast<SelectInst>(V)) {
7153       AddWork(SI->getTrueValue());
7154       AddWork(SI->getFalseValue());
7155     } else if (GetElementPtrInst *GEP = dyn_cast<GetElementPtrInst>(V)) {
7156       if (OffsetZero && !GEP->hasAllZeroIndices())
7157         return nullptr;
7158       AddWork(GEP->getPointerOperand());
7159     } else if (CallBase *CB = dyn_cast<CallBase>(V)) {
7160       Value *Returned = CB->getReturnedArgOperand();
7161       if (Returned)
7162         AddWork(Returned);
7163       else
7164         return nullptr;
7165     } else {
7166       return nullptr;
7167     }
7168   } while (!Worklist.empty());
7169 
7170   return Result;
7171 }
