411 static bool suppressSpeculativeLoadForSanitizers(const Instruction &CtxI) {
412   const Function &F = *CtxI.getFunction();
413   // Speculative load may create a race that did not exist in the source.
414   return F.hasFnAttribute(Attribute::SanitizeThread) ||
415          // Speculative load may load data from dirty regions.
416          F.hasFnAttribute(Attribute::SanitizeAddress) ||
417          F.hasFnAttribute(Attribute::SanitizeHWAddress);
418 }
