6933 const Value *llvm::getUnderlyingObject(const Value *V, unsigned MaxLookup) {
6934   for (unsigned Count = 0; MaxLookup == 0 || Count < MaxLookup; ++Count) {
6935     if (auto *GEP = dyn_cast<GEPOperator>(V)) {
6936       const Value *PtrOp = GEP->getPointerOperand();
6937       if (!PtrOp->getType()->isPointerTy()) // Only handle scalar pointer base.
6938         return V;
6939       V = PtrOp;
6940     } else if (Operator::getOpcode(V) == Instruction::BitCast ||
6941                Operator::getOpcode(V) == Instruction::AddrSpaceCast) {
6942       Value *NewV = cast<Operator>(V)->getOperand(0);
6943       if (!NewV->getType()->isPointerTy())
6944         return V;
6945       V = NewV;
6946     } else if (auto *GA = dyn_cast<GlobalAlias>(V)) {
6947       if (GA->isInterposable())
6948         return V;
6949       V = GA->getAliasee();
6950     } else {
6951       if (auto *PHI = dyn_cast<PHINode>(V)) {
6952         // Look through single-arg phi nodes created by LCSSA.
6953         if (PHI->getNumIncomingValues() == 1) {
6954           V = PHI->getIncomingValue(0);
6955           continue;
6956         }
6957       } else if (auto *Call = dyn_cast<CallBase>(V)) {
6958         // CaptureTracking can know about special capturing properties of some
6959         // intrinsics like launder.invariant.group, that can't be expressed with
6960         // the attributes, but have properties like returning aliasing pointer.
6961         // Because some analysis may assume that nocaptured pointer is not
6962         // returned from some special intrinsic (because function would have to
6963         // be marked with returns attribute), it is crucial to use this function
6964         // because it should be in sync with CaptureTracking. Not using it may
6965         // cause weird miscompilations where 2 aliasing pointers are assumed to
6966         // noalias.
6967         if (auto *RP = getArgumentAliasingToReturnedPointer(Call, false)) {
6968           V = RP;
6969           continue;
6970         }
6971       }
6972 
6973       return V;
6974     }
6975     assert(V->getType()->isPointerTy() && "Unexpected operand type!");
6976   }
6977   return V;
6978 }
