6980 void llvm::getUnderlyingObjects(const Value *V,
6981                                 SmallVectorImpl<const Value *> &Objects,
6982                                 const LoopInfo *LI, unsigned MaxLookup) {
6983   SmallPtrSet<const Value *, 4> Visited;
6984   SmallVector<const Value *, 4> Worklist;
6985   Worklist.push_back(V);
6986   do {
6987     const Value *P = Worklist.pop_back_val();
6988     P = getUnderlyingObject(P, MaxLookup);
6989 
6990     if (!Visited.insert(P).second)
6991       continue;
6992 
6993     if (auto *SI = dyn_cast<SelectInst>(P)) {
6994       Worklist.push_back(SI->getTrueValue());
6995       Worklist.push_back(SI->getFalseValue());
6996       continue;
6997     }
6998 
6999     if (auto *PN = dyn_cast<PHINode>(P)) {
7000       // If this PHI changes the underlying object in every iteration of the
7001       // loop, don't look through it.  Consider:
7002       //   int **A;
7003       //   for (i) {
7004       //     Prev = Curr;     // Prev = PHI (Prev_0, Curr)
7005       //     Curr = A[i];
7006       //     *Prev, *Curr;
7007       //
7008       // Prev is tracking Curr one iteration behind so they refer to different
7009       // underlying objects.
7010       if (!LI || !LI->isLoopHeader(PN->getParent()) ||
7011           isSameUnderlyingObjectInLoop(PN, LI))
7012         append_range(Worklist, PN->incoming_values());
7013       else
7014         Objects.push_back(P);
7015       continue;
7016     }
7017 
7018     Objects.push_back(P);
7019   } while (!Worklist.empty());
7020 }
