7022 const Value *llvm::getUnderlyingObjectAggressive(const Value *V) {
7023   const unsigned MaxVisited = 8;
7024 
7025   SmallPtrSet<const Value *, 8> Visited;
7026   SmallVector<const Value *, 8> Worklist;
7027   Worklist.push_back(V);
7028   const Value *Object = nullptr;
7029   // Used as fallback if we can't find a common underlying object through
7030   // recursion.
7031   bool First = true;
7032   const Value *FirstObject = getUnderlyingObject(V);
7033   do {
7034     const Value *P = Worklist.pop_back_val();
7035     P = First ? FirstObject : getUnderlyingObject(P);
7036     First = false;
7037 
7038     if (!Visited.insert(P).second)
7039       continue;
7040 
7041     if (Visited.size() == MaxVisited)
7042       return FirstObject;
7043 
7044     if (auto *SI = dyn_cast<SelectInst>(P)) {
7045       Worklist.push_back(SI->getTrueValue());
7046       Worklist.push_back(SI->getFalseValue());
7047       continue;
7048     }
7049 
7050     if (auto *PN = dyn_cast<PHINode>(P)) {
7051       append_range(Worklist, PN->incoming_values());
7052       continue;
7053     }
7054 
7055     if (!Object)
7056       Object = P;
7057     else if (Object != P)
7058       return FirstObject;
7059   } while (!Worklist.empty());
7060 
7061   return Object ? Object : FirstObject;
7062 }
