7092 /// This is a wrapper around getUnderlyingObjects and adds support for basic
7093 /// ptrtoint+arithmetic+inttoptr sequences.
7094 /// It returns false if unidentified object is found in getUnderlyingObjects.
7095 bool llvm::getUnderlyingObjectsForCodeGen(const Value *V,
7096                                           SmallVectorImpl<Value *> &Objects) {
7097   SmallPtrSet<const Value *, 16> Visited;
7098   SmallVector<const Value *, 4> Working(1, V);
7099   do {
7100     V = Working.pop_back_val();
7101 
7102     SmallVector<const Value *, 4> Objs;
7103     getUnderlyingObjects(V, Objs);
7104 
7105     for (const Value *V : Objs) {
7106       if (!Visited.insert(V).second)
7107         continue;
7108       if (Operator::getOpcode(V) == Instruction::IntToPtr) {
7109         const Value *O =
7110           getUnderlyingObjectFromInt(cast<User>(V)->getOperand(0));
7111         if (O->getType()->isPointerTy()) {
7112           Working.push_back(O);
7113           continue;
7114         }
7115       }
7116       // If getUnderlyingObjects fails to find an identifiable object,
7117       // getUnderlyingObjectsForCodeGen also fails for safety.
7118       if (!isIdentifiedObject(V)) {
7119         Objects.clear();
7120         return false;
7121       }
7122       Objects.push_back(const_cast<Value *>(V));
7123     }
7124   } while (!Working.empty());
7125   return true;
7126 }
