7148       AddWork(CI->getOperand(0));
7149     } else if (PHINode *PN = dyn_cast<PHINode>(V)) {
7150       for (Value *IncValue : PN->incoming_values())
7151         AddWork(IncValue);
7152     } else if (auto *SI = dyn_cast<SelectInst>(V)) {
7153       AddWork(SI->getTrueValue());
7154       AddWork(SI->getFalseValue());
7155     } else if (GetElementPtrInst *GEP = dyn_cast<GetElementPtrInst>(V)) {
7156       if (OffsetZero && !GEP->hasAllZeroIndices())
7157         return nullptr;
