7159     } else if (CallBase *CB = dyn_cast<CallBase>(V)) {
7160       Value *Returned = CB->getReturnedArgOperand();
7161       if (Returned)
7162         AddWork(Returned);
7163       else
7164         return nullptr;
7165     } else {
7166       return nullptr;
7167     }
7168   } while (!Worklist.empty());
7169 
7170   return Result;
