1659 //      SLT predicate can also be SGT iff C2 != INT_MAX (+invert res.)
1660 static Value *canonicalizeClampLike(SelectInst &Sel0, ICmpInst &Cmp0,
1661                                     InstCombiner::BuilderTy &Builder,
1662                                     InstCombiner &IC) {
